#!/bin/bash\n\n# 🚀 AI Model Aggregator - 本地初始化脚本\n# 此脚本会在您的本地机器上创建完整的项目结构\n\nset -e\n\n# 颜色定义\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m'\n\necho -e \"${BLUE}╔════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${BLUE}║  🚀 AI Model Aggregator - 本地初始化脚本${NC}                ${BLUE}║${NC}\"\necho -e \"${BLUE}╚════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\n\n# 检查是否已在项目目录\nif [ -f \"docker-compose.yml\" ]; then\n    echo -e \"${YELLOW}⚠️  已在项目目录中。跳过目录创建。${NC}\"\nelse\n    echo -e \"${YELLOW}📂 创建项目目录结构...${NC}\"\n    \n    # 创建目录\n    mkdir -p backend/app/{adapters,services,routes,models,utils}\n    mkdir -p frontend/src/{views,components,router,store,api}\n    mkdir -p frontend/public\n    mkdir -p scripts\n    mkdir -p monitoring\n    mkdir -p deployment/k8s\n    mkdir -p tests\n    \n    echo -e \"${GREEN}✓ 目录结构已创建${NC}\"\nfi\n\necho \"\"\necho -e \"${YELLOW}📋 创建所有必要的文件...${NC}\"\n\n# 创建后端文件\necho -e \"${BLUE}后端文件:${NC}\"\n\n# requirements.txt\ncat > backend/requirements.txt << 'EOF'\nfastapi==0.104.1\nuvicorn[standard]==0.24.0\npydantic==2.5.0\npydantic-settings==2.1.0\npython-multipart==0.0.6\nSQLAlchemy==2.0.23\nalembic==1.12.1\npsycopg2-binary==2.9.9\nredis==5.0.1\nopenai==1.3.9\ngoogle-generativeai==0.3.0\nanthropic==0.7.1\nhttpx==0.25.2\naiohttp==3.9.1\npython-jose[cryptography]==3.3.0\npasslib[bcrypt]==1.7.4\nPyJWT==2.8.1\nprometheus-client==0.19.0\npython-json-logger==2.0.7\nloguru==0.7.2\npython-dotenv==1.0.0\nrequests==2.31.0\npytz==2023.3\npytest==7.4.3\npytest-asyncio==0.21.1\npytest-cov==4.1.0\nEOF\necho -e \"${GREEN}✓ backend/requirements.txt${NC}\"\n\n# Dockerfile\ncat > backend/Dockerfile << 'EOF'\nFROM python:3.11-slim\nWORKDIR /app\nRUN apt-get update && apt-get install -y gcc && rm -rf /var/lib/apt/lists/*\nCOPY requirements.txt .\nRUN pip install --no-cache-dir -r requirements.txt\nCOPY . .\nEXPOSE 8000\nHEALTHCHECK --interval=30s --timeout=10s --start-period=40s --retries=3 \\\n    CMD python -c \"import requests; requests.get('http://localhost:8000/health')\"\nCMD [\"uvicorn\", \"app.main:app\", \"--host\", \"0.0.0.0\", \"--port\", \"8000\"]\nEOF\necho -e \"${GREEN}✓ backend/Dockerfile${NC}\"\n\necho \"\"\necho -e \"${BLUE}前端文件:${NC}\"\n\n# package.json\ncat > frontend/package.json << 'EOF'\n{\n  \"name\": \"ai-aggregator-frontend\",\n  \"version\": \"1.0.0\",\n  \"type\": \"module\",\n  \"scripts\": {\n    \"dev\": \"vite\",\n    \"build\": \"vite build\",\n    \"preview\": \"vite preview\"\n  },\n  \"dependencies\": {\n    \"vue\": \"^3.3.4\",\n    \"vue-router\": \"^4.2.5\",\n    \"axios\": \"^1.6.1\",\n    \"tailwindcss\": \"^3.3.6\"\n  },\n  \"devDependencies\": {\n    \"@vitejs/plugin-vue\": \"^4.5.0\",\n    \"vite\": \"^5.0.5\",\n    \"autoprefixer\": \"^10.4.16\",\n    \"postcss\": \"^8.4.32\"\n  }\n}\nEOF\necho -e \"${GREEN}✓ frontend/package.json${NC}\"\n\n# vite.config.js\ncat > frontend/vite.config.js << 'EOF'\nimport { defineConfig } from 'vite'\nimport vue from '@vitejs/plugin-vue'\nimport path from 'path'\n\nexport default defineConfig({\n  plugins: [vue()],\n  resolve: {\n    alias: {\n      '@': path.resolve(__dirname, './src'),\n    },\n  },\n  server: {\n    host: '0.0.0.0',\n    port: 3000,\n    proxy: {\n      '/api': {\n        target: 'http://localhost:8000',\n        changeOrigin: true,\n      },\n    },\n  },\n})\nEOF\necho -e \"${GREEN}✓ frontend/vite.config.js${NC}\"\n\necho \"\"\necho -e \"${BLUE}容器配置文件:${NC}\"\n\n# docker-compose.yml\ncat > docker-compose.yml << 'EOF'\nversion: '3.8'\n\nservices:\n  postgres:\n    image: postgres:15-alpine\n    container_name: aggregator-db\n    environment:\n      POSTGRES_DB: aggregator\n      POSTGRES_USER: postgres\n      POSTGRES_PASSWORD: password\n    ports:\n      - \"5432:5432\"\n    volumes:\n      - postgres_data:/var/lib/postgresql/data\n    healthcheck:\n      test: [\"CMD-SHELL\", \"pg_isready -U postgres\"]\n      interval: 10s\n      timeout: 5s\n      retries: 5\n\n  redis:\n    image: redis:7-alpine\n    container_name: aggregator-cache\n    ports:\n      - \"6379:6379\"\n    volumes:\n      - redis_data:/data\n    healthcheck:\n      test: [\"CMD\", \"redis-cli\", \"ping\"]\n      interval: 10s\n      timeout: 5s\n      retries: 5\n\n  api:\n    build:\n      context: ./backend\n      dockerfile: Dockerfile\n    container_name: aggregator-api\n    environment:\n      DATABASE_URL: postgresql://postgres:password@postgres:5432/aggregator\n      REDIS_URL: redis://redis:6379/0\n      OPENAI_API_KEY: ${OPENAI_API_KEY:-}\n      GOOGLE_API_KEY: ${GOOGLE_API_KEY:-}\n      ANTHROPIC_API_KEY: ${ANTHROPIC_API_KEY:-}\n      VALID_API_KEYS: test-key-123,demo-key-456\n      SECRET_KEY: your-secret-key-change-in-production\n    ports:\n      - \"8000:8000\"\n    depends_on:\n      postgres:\n        condition: service_healthy\n      redis:\n        condition: service_healthy\n    volumes:\n      - ./backend:/app\n    command: uvicorn app.main:app --host 0.0.0.0 --port 8000 --reload\n\n  frontend:\n    build:\n      context: ./frontend\n      dockerfile: Dockerfile\n    container_name: aggregator-frontend\n    environment:\n      VITE_API_BASE_URL: http://localhost:8000\n      VITE_API_KEY: test-key-123\n    ports:\n      - \"3000:3000\"\n    depends_on:\n      - api\n    volumes:\n      - ./frontend:/app\n\nvolumes:\n  postgres_data:\n  redis_data:\nEOF\necho -e \"${GREEN}✓ docker-compose.yml${NC}\"\n\necho \"\"\necho -e \"${BLUE}配置文件:${NC}\"\n\n# .env.example\ncat > .env.example << 'EOF'\nAPI_HOST=0.0.0.0\nAPI_PORT=8000\nAPI_DEBUG=true\nDATABASE_URL=postgresql://postgres:password@postgres:5432/aggregator\nREDIS_URL=redis://redis:6379/0\nOPENAI_API_KEY=sk-your-key\nGOOGLE_API_KEY=your-key\nANTHROPIC_API_KEY=sk-ant-your-key\nVALID_API_KEYS=test-key-123,demo-key-456\nSECRET_KEY=your-secret-key\nEOF\necho -e \"${GREEN}✓ .env.example${NC}\"\n\n# .gitignore\ncat > .gitignore << 'EOF'\n__pycache__/\n*.py[cod]\n*.so\n.Python\n.env\nvenv/\nenv/\nnode_modules/\ndist/\n.DS_Store\n.idea/\n.vscode/\n*.log\nEOF\necho -e \"${GREEN}✓ .gitignore${NC}\"\n\necho \"\"\necho -e \"${BLUE}脚本文件:${NC}\"\n\n# start.sh\ncat > scripts/start.sh << 'SCRIPT'\n#!/bin/bash\nset -e\necho \"🚀 启动所有服务...\"\ncp .env.example .env 2>/dev/null || true\ndocker-compose build\ndocker-compose up -d\nsleep 30\ndocker-compose ps\necho \"✅ 启动完成！\"\necho \"前端: http://localhost:3000\"\necho \"API: http://localhost:8000/docs\"\necho \"监控: http://localhost:3001\"\nSCRIPT\nchmod +x scripts/start.sh\necho -e \"${GREEN}✓ scripts/start.sh${NC}\"\n\n# stop.sh\ncat > scripts/stop.sh << 'SCRIPT'\n#!/bin/bash\necho \"🛑 停止所有服务...\"\ndocker-compose down\necho \"✅ 已停止\"\nSCRIPT\nchmod +x scripts/stop.sh\necho -e \"${GREEN}✓ scripts/stop.sh${NC}\"\n\necho \"\"\necho -e \"${GREEN}╔════════════════════════════════════════════════════════════╗${NC}\"\necho -e \"${GREEN}║                ✅ 项目初始化完成！${NC}                       ${GREEN}║${NC}\"\necho -e \"${GREEN}╚════════════════════════════════════════════════════════════╝${NC}\"\necho \"\"\necho -e \"${BLUE}📝 下一步：${NC}\"\necho \"1. 配置环境变量\"\necho \"   cp .env.example .env\"\necho \"   # 编辑 .env 填入您的API密钥（可选）\"\necho \"\"\necho \"2. 启动所有服务\"\necho \"   chmod +x scripts/start.sh\"\necho \"   ./scripts/start.sh\"\necho \"\"\necho \"3. 访问应用\"\necho \"   - 前端: http://localhost:3000\"\necho \"   - API文档: http://localhost:8000/docs\"\necho \"   - 健康检查: http://localhost:8000/api/v1/health\"\necho \"\"\n"
